exercises.solution_code:
#include <iostream>
#include <string>

struct Address
{
    std::string city;
    int zip;
};

struct Person
{
    std::string name;
    Address address;
};

int main()
{
    std::string name1, city1, name2, city2;
    int zip1, zip2;

    std::cin >> name1 >> city1 >> zip1;
    std::cin >> name2 >> city2 >> zip2;

    Person p1{ name1, { city1, zip1 } };
    Person p2{ name2, { city2, zip2 } };

    std::cout << p1.name << ": " << p1.address.city << ' ' << p1.address.zip << '\n';
    std::cout << p2.name << ": " << p2.address.city << ' ' << p2.address.zip << '\n';
    std::cout << "sizeof(Person) = " << sizeof(Person) << '\n';

    return 0;
}

